  ('dietitian-moex-04754', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '異環胺類化合物（heterocyclicamines）為食品加工過程中衍生之有毒物質，下列敘述何者錯誤？', '["異環胺類化合物為蛋白質食品進行高溫加熱後產生，可分為 IQ 類化合物、非 IQ 類化合物與 carboline類化合物三大類", "Trp-p-1與Glu-p-1分別是色胺酸與麩胺酸的高溫裂解產物，屬於非IQ類化合物，不需S-9mix 即可表現強致突變性", "高溫是促進異環胺類化合物形成的關鍵因素，水分則是其抑制因子", "各種異環胺類化合物以MeIQ致癌性最強"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04755', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品添加物使用範圍及限量暨規格標準，下列何者為漂白劑？', '["碳酸鉀（potassiumcarbonate）", "亞硫酸鈉（sodiumsulfite）", "脂肪酸甘油酯（glycerinfattyacidester）", "矽樹脂（siliconresin）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04756', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關壬基苯酚類（nonylphenol及nonylphenolethoxylate）化合物之特性及應用，下列敘述何者錯誤？', '["屬於環境荷爾蒙", "構造類似動物的雄性激素", "會降低魚類的繁殖能力", "可添加在食品用洗潔劑中"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04757', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '質量輕、韌性佳、耐酸鹼，可盛裝果汁、碳酸飲料等多種液體，俗稱寶特瓶的容器，其分子結構 是一種：', '["聚對苯二甲酸乙二酯（polyethyleneterephthalate）", "聚偏二氯乙烯（polyvinylidenedichloride）", "聚苯乙烯（polystyrene）", "聚碳酸酯（polycarbonate）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04758', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '食品用洗潔劑於波長 365 nm 之紫外燈下觀察，表面發出紫－藍白色之光線，則此洗潔劑可能含 有何種成分？', '["砷", "壬基苯酚類界面活性劑", "螢光增白劑", "甲醇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04759', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品器具、食品容器或包裝標示相關規定，食品接觸面含何種材質之食品容器應註明「勿與 高油脂且高溫之食品直接接觸」之警語？', '["不銹鋼200系列", "不銹鋼300系列", "聚氯乙烯（PVC）", "聚丙烯（PP）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04760', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '一般家庭用的洗碗精多屬於下列何類洗潔劑？', '["陰離子界面活性劑", "陽離子界面活性劑", "兩性界面活性劑", "非離子界面活性劑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04761', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何種寄生蟲主要不是經由生食蔬菜類食物感染？', '["蟯蟲", "鉤蟲", "蛔蟲", "絛蟲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04762', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '關於庫賈氏病之敘述，下列何者錯誤？', '["是由一種具感染性的普利昂蛋白（prion）造成，使腦組織變成海綿樣的疾病", "與牛海綿狀腦病（bovinespongiformencephalopathy）有高度相關性", "因誤食遭受污染的牛肉或相關內臟、骨粉，通常於一年內發病", "又稱為人類傳播性海綿樣腦症（humantransmissiblespongiformencephalopathies）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04763', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關細菌性中間型食物中毒（foodbornetoxin-mediatedinfection），下列敘述何者正確？', '["因食用受病原菌污染且產生毒素之食品，所引起疾病之現象", "此類食品中毒菌包括肉毒桿菌（Clostridiumbotulinum）", "因病原菌經由攝食進入人體後，於人體繁殖且產生毒素引起疾病", "此類食品中毒菌包括腸炎弧菌（Vibrioparahaemolyticus）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "12a577cea64a", "answer_pdf_sha1": "3f9398e1ab67", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
